import{_ as e,o as l,c as t,a2 as r}from"./chunks/framework.Crpw6aS5.js";const _=JSON.parse('{"title":"1986年巴菲特致股东的信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1986年/核心总结.md","filePath":"01_letters/1986年/核心总结.md"}'),i={name:"01_letters/1986年/核心总结.md"};function o(h,a,n,s,p,c){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="_1986年巴菲特致股东的信核心总结" tabindex="-1">1986年巴菲特致股东的信核心总结 <a class="header-anchor" href="#_1986年巴菲特致股东的信核心总结" aria-label="Permalink to &quot;1986年巴菲特致股东的信核心总结&quot;">​</a></h1><h2 id="简要导读" tabindex="-1">简要导读 <a class="header-anchor" href="#简要导读" aria-label="Permalink to &quot;简要导读&quot;">​</a></h2><p>1986年这封信，巴菲特讲透了伯克希尔的管理哲学，为什么我们能做到这么好，核心就是&quot;只和我们喜欢欣赏的人合作&quot;，以及<strong>资本配置的纪律</strong>：市场高估没机会，宁愿拿着现金等，绝不乱买，这个原则放到今天依然非常适用。文末可下载英文原版PDF。</p><h2 id="一、伯克希尔的管理秘诀-找对人-不挡道" tabindex="-1">一、伯克希尔的管理秘诀：找对人，不挡道 <a class="header-anchor" href="#一、伯克希尔的管理秘诀-找对人-不挡道" aria-label="Permalink to &quot;一、伯克希尔的管理秘诀：找对人，不挡道&quot;">​</a></h2><p>巴菲特说，查理和我其实只有两个工作：</p><ol><li>吸引留住出色经理人，让他们运营各个业务——我们买公司的时候，经理人早就证明了自己，我们主要工作就是别挡道，就像你雇了杰克·尼克劳斯帮你打高尔夫，你不需要教他怎么挥杆。</li><li>配置资本，这个对伯克希尔特别重要，因为我们赚得多，全部留存，不需要太多新增资本，所以资本配置决策影响比一般公司大得多。</li></ol><p>我们坚持只和我们喜欢欣赏的人合作，这个政策不仅最大化好结果概率，还能让我们过得特别开心，和让你胃不舒服的人合作，就像为了钱结婚，本来就不对，你已经有钱了，还这么干，绝对疯了。</p><p>所以，你看到现在，我们主要业务经理，个个都像所有者一样思考，我们完全放心，这种文化天然就能扩张，我们能管双倍现在经理，只要他们有现在这些品质。</p><h2 id="二、收购了fechheimer-标准就是我们一直说的标准" tabindex="-1">二、收购了Fechheimer，标准就是我们一直说的标准 <a class="header-anchor" href="#二、收购了fechheimer-标准就是我们一直说的标准" aria-label="Permalink to &quot;二、收购了Fechheimer，标准就是我们一直说的标准&quot;">​</a></h2><p>Fechheimer做制服，完全符合我们所有标准：</p><ul><li>管理层自己喜欢，愿意继续持股经营</li><li>资本回报率好，负债少</li><li>业务简单我们能懂</li><li>报价明确</li><li>合适规模。</li></ul><p>我们再重申一遍收购标准，现在最低税后盈利要求从500万涨到1000万了，符合标准欢迎联系我们。</p><h2 id="三、保险行业-现在终于轮到我们了" tabindex="-1">三、保险行业：现在终于轮到我们了 <a class="header-anchor" href="#三、保险行业-现在终于轮到我们了" aria-label="Permalink to &quot;三、保险行业：现在终于轮到我们了&quot;">​</a></h2><p>巴菲特还是老结论：保险就是大宗商品生意，只有产能短缺才能赚大钱，产能不缺赚不到钱，现在前些年亏了很多，很多不敢做了，所以产能紧了，我们资本够强，所以我们拿到很多好生意，这两年保费增长飞快，1986年综合成本率降到103，过去111。</p><p>但是他也预测，好了一阵子，大家又会融资本进来，产能又过剩，价格又下来，所以现在好，过几年又会坏，这就是周期。</p><p>GEICO现在越来越棒，成本不断降，护城河越来越宽，卢·辛普森投资成绩真出色，连续几年跑赢标普，太厉害了。</p><h2 id="四、现在市场太高-我们找不到便宜股票-怎么办" tabindex="-1">四、现在市场太高，我们找不到便宜股票，怎么办？ <a class="header-anchor" href="#四、现在市场太高-我们找不到便宜股票-怎么办" aria-label="Permalink to &quot;四、现在市场太高，我们找不到便宜股票，怎么办？&quot;">​</a></h2><p>巴菲特说，我们规则从来就是：<strong>别人恐惧我贪婪，别人贪婪我恐惧</strong>，现在华尔街到处都是贪婪，没有恐惧，所以我们找不到便宜股票，就拿着等着，我们知道市场永远会周期性爆发恐惧贪婪，我们等着就好。</p><p>现在牛市，大家都兴奋，但是记住，整体投资者长期回报不可能超过企业整体盈利，交易成本管理费吃掉很多，所以投资者回报一定低于企业盈利，牛市掩盖不了这个数学规律，改变不了。</p><p>我们三大重仓股首都城市、GEICO、华盛顿邮报，我们永远不卖，不管高估低估，就像我们不卖喜诗、水牛城新闻，我们就是要拿着好生意不动，这就是我们风格。</p><h2 id="五、新税法对伯克希尔有什么影响" tabindex="-1">五、新税法对伯克希尔有什么影响 <a class="header-anchor" href="#五、新税法对伯克希尔有什么影响" aria-label="Permalink to &quot;五、新税法对伯克希尔有什么影响&quot;">​</a></h2><p>整体净影响是负面的：</p><ul><li>资本利得税从20%涨到28%，所以未来你拿到税后收益会少一点，我们本来很多收益都是资本利得。</li><li>保险公司股息利息税负重了，未来投资收益至少降10%。</li><li>好消息是公司所得税从46%降到34%，这个好处我们这些有强品牌的企业自己拿了，不会传给消费者，所以对我们是好事。</li></ul><p>总的来说，新税法让我们未来增长慢一点，这个影响是确定的。</p><h2 id="六、核心启示" tabindex="-1">六、核心启示 <a class="header-anchor" href="#六、核心启示" aria-label="Permalink to &quot;六、核心启示&quot;">​</a></h2><ol><li>管理没那么复杂，找对人，相信人，别挡道，就够了，我们很多人就是忍不住瞎指挥，反而坏了事。</li><li>没机会别乱出手，市场永远有机会，牛市没人便宜卖，你就等熊市，拿着现金不丢人，乱买才丢人。</li><li>好企业拿着不动，比换来换去赚得多，这才是真正的长期投资。</li></ol><hr><blockquote><p>📎 <strong>文末小惊喜</strong>：可点击下载<a href="Chairman&#39;s%20Letter%20-%201986.pdf">巴菲特1986年股东信原件PDF</a>，原汁原味阅读英文原文。</p></blockquote>',28)])])}const u=e(i,[["render",o]]);export{_ as __pageData,u as default};
